        if (length(v_s) && length(v_c) && !is.na(v_s) && !is.na(v_c)) {
          n_tot_q3 <- n_tot_q3 + 1L
          if (v_c > v_s) n_worse <- n_worse + 1L
          else n_better <- n_better + 1L
        }
      }
    }
  }
}
pct_worse <- round(100 * n_worse / n_tot_q3)

